import { Component, OnInit } from '@angular/core';
import { FormArray, FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { GeneratedResume, ResumeTemplate } from '../../../core/models/resume.model';
import { ResumeBuilderLocalService } from '../../../core/services/resume-builder-local.service';
import { ResumeService } from '../../../core/services/resume.service';

@Component({
  selector: 'app-resume-editor',
  templateUrl: './resume-editor.component.html'
})
export class ResumeEditorComponent implements OnInit {
  resume: GeneratedResume | null = null;
  template: ResumeTemplate | null = null;
  activeTab: 'overview' | 'content' | 'customize' | 'ai' = 'content';
  loading = true;
  saving = false;
  error = '';

  readonly form = this.formBuilder.group({
    title: ['', Validators.required],
    fullName: ['', Validators.required],
    headline: [''],
    email: ['', [Validators.required, Validators.email]],
    phone: ['', Validators.required],
    links: [''],
    education: this.formBuilder.array([]),
    skills: this.formBuilder.array([]),
    projects: this.formBuilder.array([]),
    experience: this.formBuilder.array([]),
    certifications: this.formBuilder.array([]),
    achievements: this.formBuilder.array([]),
    languages: this.formBuilder.array([]),
    designFont: ['Source Sans Pro'],
    designAccent: ['#59707c'],
    designText: ['#111827'],
    pageFormat: ['A4']
  });

  readonly fontOptions = ['Source Sans Pro', 'Karla', 'Mulish', 'Lato', 'Roboto', 'Work Sans'];
  readonly accentOptions = ['#59707c', '#2563eb', '#7c3aed', '#0f766e', '#b45309', '#1f2937'];

  constructor(
    private readonly formBuilder: FormBuilder,
    private readonly route: ActivatedRoute,
    private readonly router: Router,
    private readonly resumeBuilderLocalService: ResumeBuilderLocalService,
    private readonly resumeService: ResumeService
  ) {
  }

  ngOnInit(): void {
    const resumeId = Number(this.route.snapshot.paramMap.get('resumeId'));
    this.resume = this.resumeBuilderLocalService.getResume(resumeId);
    if (!this.resume) {
      this.loading = false;
      return;
    }
    this.resumeService.getTemplateDetail(this.resume.templateId).subscribe({
      next: (template) => {
        this.template = template;
        this.populateForm(this.resume!);
        this.loading = false;
      },
      error: () => {
        this.loading = false;
      }
    });
  }

  get education(): FormArray {
    return this.form.get('education') as FormArray;
  }

  get skills(): FormArray {
    return this.form.get('skills') as FormArray;
  }

  get projects(): FormArray {
    return this.form.get('projects') as FormArray;
  }

  get experience(): FormArray {
    return this.form.get('experience') as FormArray;
  }

  get certifications(): FormArray {
    return this.form.get('certifications') as FormArray;
  }

  get achievements(): FormArray {
    return this.form.get('achievements') as FormArray;
  }

  get languages(): FormArray {
    return this.form.get('languages') as FormArray;
  }

  get previewHtml(): string {
    if (!this.template) {
      return '';
    }
    return this.resumeBuilderLocalService.buildPreviewHtml(
      this.template,
      (this.form.value.title as string) || this.resume?.title || 'Resume',
      this.form.getRawValue() as Record<string, unknown>
    );
  }

  addItem(array: FormArray): void {
    array.push(this.createLineControl(''));
  }

  removeItem(array: FormArray, index: number): void {
    if (array.length > 1) {
      array.removeAt(index);
    }
  }

  save(): void {
    if (this.form.invalid || !this.resume || !this.template) {
      this.form.markAllAsTouched();
      return;
    }

    this.saving = true;
    this.error = '';

    try {
      const updated = this.resumeBuilderLocalService.updateResume(
        this.resume.id,
        this.template,
        this.form.value.title as string,
        this.form.getRawValue() as Record<string, unknown>
      );
      this.router.navigate(['/resume-builder/preview', updated.id]);
    } catch (error) {
      this.saving = false;
      this.error = error instanceof Error ? error.message : 'Failed to save resume.';
    }
  }

  private populateForm(resume: GeneratedResume): void {
    const data = JSON.parse(resume.resumeDataJson) as Record<string, unknown>;
    this.form.patchValue({
      title: this.stringValue(data['title'], resume.title),
      fullName: this.stringValue(data['fullName']),
      headline: this.stringValue(data['headline']),
      email: this.stringValue(data['email']),
      phone: this.stringValue(data['phone']),
      links: this.stringValue(data['links'])
    });

    this.resetArray(this.education, data['education']);
    this.resetArray(this.skills, data['skills']);
    this.resetArray(this.projects, data['projects']);
    this.resetArray(this.experience, data['experience']);
    this.resetArray(this.certifications, data['certifications']);
    this.resetArray(this.achievements, data['achievements']);
    this.resetArray(this.languages, data['languages']);
  }

  private resetArray(array: FormArray, value: unknown): void {
    while (array.length) {
      array.removeAt(0);
    }

    const items = Array.isArray(value) ? value as Array<{ value?: string }> : [];
    if (items.length === 0) {
      array.push(this.createLineControl(''));
      return;
    }

    items.forEach((item) => {
      array.push(this.createLineControl(item?.value ?? ''));
    });
  }

  private createLineControl(initialValue = ''): FormGroup {
    return this.formBuilder.group({
      value: [initialValue, Validators.required]
    });
  }

  private stringValue(value: unknown, fallback = ''): string {
    return typeof value === 'string' ? value : fallback;
  }
}
<app-loader *ngIf="loading" message="Loading editable resume"></app-loader>

<div *ngIf="!loading && resume && template" class="space-y-4">
  <div class="glass-panel flex flex-wrap items-center justify-between gap-4 px-4 py-3">
    <div class="flex flex-wrap gap-3">
      <button type="button" class="rounded-2xl px-5 py-3 font-semibold transition" [ngClass]="activeTab === 'overview' ? 'bg-ink text-white' : 'bg-white text-ink'" (click)="activeTab = 'overview'">Overview</button>
      <button type="button" class="rounded-2xl px-5 py-3 font-semibold transition" [ngClass]="activeTab === 'content' ? 'bg-poppy/10 text-poppy' : 'bg-white text-ink'" (click)="activeTab = 'content'">Content</button>
      <button type="button" class="rounded-2xl px-5 py-3 font-semibold transition" [ngClass]="activeTab === 'customize' ? 'bg-poppy/10 text-poppy' : 'bg-white text-ink'" (click)="activeTab = 'customize'">Customize</button>
      <button type="button" class="rounded-2xl px-5 py-3 font-semibold transition" [ngClass]="activeTab === 'ai' ? 'bg-poppy/10 text-poppy' : 'bg-white text-ink'" (click)="activeTab = 'ai'">AI Tools</button>
    </div>

    <div class="flex gap-3">
      <span class="rounded-2xl bg-white px-4 py-3 text-sm font-semibold text-ink">{{ resume.title }}</span>
      <button class="btn-primary" type="button" (click)="save()" [disabled]="saving">{{ saving ? 'Saving...' : 'Save' }}</button>
    </div>
  </div>

  <form class="grid gap-4 xl:grid-cols-[0.52fr_0.48fr]" [formGroup]="form" (ngSubmit)="save()">
    <section class="space-y-4">
      <div *ngIf="activeTab === 'overview'" class="glass-panel p-6">
        <p class="text-sm font-semibold uppercase tracking-[0.28em] text-poppy">Builder Overview</p>
        <h2 class="section-title mt-2 text-4xl">{{ template.name }}</h2>
        <p class="mt-4 text-base leading-7 text-ink/65">
          Edit content and customization on the left. The preview updates instantly on the right, closer to the advanced builder flow you referenced.
        </p>
      </div>

      <div *ngIf="activeTab === 'content'" class="space-y-4">
        <section class="glass-panel p-6">
          <h3 class="section-title text-3xl">Profile</h3>
          <div class="mt-5 grid gap-4 md:grid-cols-2">
            <input class="field" formControlName="title" placeholder="Resume title">
            <input class="field" formControlName="fullName" placeholder="Full name">
            <input class="field" formControlName="headline" placeholder="Headline">
            <input class="field" formControlName="email" placeholder="Email">
            <input class="field" formControlName="phone" placeholder="Phone">
            <input class="field" formControlName="links" placeholder="Links">
          </div>
        </section>

        <section class="glass-panel p-6">
          <h3 class="section-title text-3xl">Experience</h3>
          <div formArrayName="experience" class="mt-4 space-y-3">
            <div *ngFor="let group of experience.controls; let i = index" [formGroupName]="i" class="flex gap-3">
              <input class="field" formControlName="value" placeholder="Experience / internship bullet">
              <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(experience, i)">Remove</button>
            </div>
          </div>
          <button class="btn-secondary mt-3" type="button" (click)="addItem(experience)">Add Experience</button>
        </section>

        <section class="glass-panel p-6">
          <h3 class="section-title text-3xl">Projects</h3>
          <div formArrayName="projects" class="mt-4 space-y-3">
            <div *ngFor="let group of projects.controls; let i = index" [formGroupName]="i" class="flex gap-3">
              <input class="field" formControlName="value" placeholder="Project bullet">
              <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(projects, i)">Remove</button>
            </div>
          </div>
          <button class="btn-secondary mt-3" type="button" (click)="addItem(projects)">Add Project</button>
        </section>

        <section class="glass-panel p-6">
          <div class="grid gap-6 lg:grid-cols-2">
            <div>
              <h3 class="section-title text-2xl">Skills</h3>
              <div formArrayName="skills" class="mt-4 space-y-3">
                <div *ngFor="let group of skills.controls; let i = index" [formGroupName]="i" class="flex gap-3">
                  <input class="field" formControlName="value" placeholder="Skill entry">
                  <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(skills, i)">Remove</button>
                </div>
              </div>
              <button class="btn-secondary mt-3" type="button" (click)="addItem(skills)">Add Skill</button>
            </div>

            <div>
              <h3 class="section-title text-2xl">Education</h3>
              <div formArrayName="education" class="mt-4 space-y-3">
                <div *ngFor="let group of education.controls; let i = index" [formGroupName]="i" class="flex gap-3">
                  <input class="field" formControlName="value" placeholder="Education entry">
                  <button class="btn-secondary px-4 py-3" type="button" (click)="removeItem(education, i)">Remove</button>
                </div>
              </div>
              <button class="btn-secondary mt-3" type="button" (click)="addItem(education)">Add Education</button>
            </div>
          </div>
        </section>
      </div>

      <div *ngIf="activeTab === 'customize'" class="space-y-4">
        <section class="glass-panel p-6">
          <h3 class="section-title text-3xl">Fonts</h3>
          <div class="mt-5 grid gap-3 md:grid-cols-2">
            <button *ngFor="let font of fontOptions" type="button" class="rounded-2xl border px-4 py-4 text-left font-semibold transition"
                    [ngClass]="form.value.designFont === font ? 'border-blue-500 bg-blue-50 text-blue-600' : 'border-black/10 bg-white text-ink'"
                    (click)="form.patchValue({ designFont: font })">
              {{ font }}
            </button>
          </div>
        </section>

        <section class="glass-panel p-6">
          <h3 class="section-title text-3xl">Colors</h3>
          <div class="mt-5 flex flex-wrap gap-4">
            <button *ngFor="let color of accentOptions" type="button" class="h-14 w-14 rounded-full border-4 transition"
                    [style.background]="color"
                    [ngClass]="form.value.designAccent === color ? 'border-ink scale-110' : 'border-white'"
                    (click)="form.patchValue({ designAccent: color })"></button>
          </div>
        </section>

        <section class="glass-panel p-6">
          <h3 class="section-title text-3xl">Language & Region</h3>
          <div class="mt-5 grid gap-4 md:grid-cols-2">
            <select class="field" formControlName="pageFormat">
              <option value="A4">A4</option>
              <option value="Letter">Letter</option>
            </select>
            <input class="field" formControlName="designText" placeholder="Text color hex">
          </div>
        </section>
      </div>

      <div *ngIf="activeTab === 'ai'" class="glass-panel p-6">
        <h3 class="section-title text-3xl">AI Tools</h3>
        <p class="mt-4 text-base leading-7 text-ink/65">
          This is the right place for role-targeted rewrite, ATS keyword tuning, and bullet improvements once the product reaches that stage.
        </p>
      </div>

      <p *ngIf="error" class="rounded-2xl bg-poppy/10 px-4 py-3 text-sm font-medium text-poppy">{{ error }}</p>
    </section>

    <section class="glass-panel overflow-hidden p-3">
      <div class="rounded-[2rem] bg-[#ece8df] p-3">
        <iframe class="h-[1100px] w-full rounded-[1.5rem] border-0 bg-white" [srcdoc]="previewHtml"></iframe>
      </div>
    </section>
  </form>
</div>
